var sdk=window.CueStack;
function u(el){var v=el.value+(el.id==='waste'?'%':'');document.getElementById(el.id+'_v').textContent=v;updatePreview()}
function log(m){var el=document.getElementById('log');el.textContent+=m+'\n';el.scrollTop=el.scrollHeight}

// Equipment transient profiles (from HVAC engineering)
var PROFILES={
  ac:{name:'Split AC',startupSpike:3.0,spikeDur:2,transientPower:1.3,transientDur:120,steadyOsc:0.08,shutdownSpike:1.1,shutdownDur:1,standby:0.03,minOn:120,minOff:60,pulldown:true},
  chiller:{name:'Chiller',startupSpike:6.0,spikeDur:2,transientPower:1.3,transientDur:60,steadyOsc:0.05,shutdownSpike:1.2,shutdownDur:1,standby:0.02,minOn:300,minOff:180,pulldown:true},
  ahu:{name:'AHU',startupSpike:2.0,spikeDur:1,transientPower:1.15,transientDur:30,steadyOsc:0.04,shutdownSpike:1.05,shutdownDur:0.5,standby:0.05,minOn:60,minOff:30,pulldown:false},
  motor:{name:'Motor/Pump',startupSpike:5.0,spikeDur:3,transientPower:1.2,transientDur:15,steadyOsc:0.03,shutdownSpike:1.3,shutdownDur:2,standby:0.01,minOn:30,minOff:10,pulldown:false},
  led:{name:'LED Lighting',startupSpike:1.0,spikeDur:0,transientPower:1.0,transientDur:0,steadyOsc:0.01,shutdownSpike:1.0,shutdownDur:0,standby:0,minOn:0,minOff:0,pulldown:false}
};

// Generate power value at a given time offset within an ON cycle
function eqPower(profile,rated,secInCycle,cycleDur,waste,Te,setpoint){
  var p=profile,r=rated*waste;
  // Startup spike (LRA)
  if(secInCycle<p.spikeDur) return r*p.startupSpike*(1+(Math.random()-0.5)*0.1);
  // Transient ramp-down
  if(secInCycle<p.spikeDur+p.transientDur){
    var prog=(secInCycle-p.spikeDur)/p.transientDur;
    var base=r*(p.transientPower-(p.transientPower-1)*prog);
    return base*(1+(Math.random()-0.5)*p.steadyOsc);
  }
  // Pulldown phase (HVAC: high power cooling room down)
  if(p.pulldown && secInCycle<p.spikeDur+p.transientDur+7200){
    var pdProg=Math.min(1,(secInCycle-p.spikeDur-p.transientDur)/7200);
    var pdFactor=1.0-pdProg*0.4; // starts at rated, drops to 60% as room cools
    var teFactor=Math.max(0.5,(Te-setpoint)/15); // outdoor temp effect
    return r*pdFactor*teFactor*(1+(Math.random()-0.5)*p.steadyOsc);
  }
  // Steady state with cycling oscillation
  var osc=Math.sin(secInCycle*0.01)*p.steadyOsc;
  var load=p.pulldown?0.5+0.1*((Te-setpoint)/10):0.7; // HVAC load depends on delta-T
  return r*load*(1+osc)*(1+(Math.random()-0.5)*p.steadyOsc*2);
}

function offPower(profile,rated){
  return rated*profile.standby+(Math.random()*5);
}

// Preview transient pattern on canvas
function updatePreview(){
  var type=document.getElementById('eqType').value;
  var p=PROFILES[type];
  var rated=parseInt(document.getElementById('rated').value);
  var Te=parseInt(document.getElementById('te').value);
  var el=document.getElementById('preview');
  el.innerHTML='<canvas id="pvCanvas"></canvas><div style="color:#94a3b8;font-size:10px;margin-top:4px">'+p.name+': startup spike '+p.startupSpike+'x ('+p.spikeDur+'s) \u2192 transient '+p.transientPower+'x ('+p.transientDur+'s) \u2192 steady \u00b1'+Math.round(p.steadyOsc*100)+'% \u2192 shutdown '+p.shutdownSpike+'x</div>';
  var c=document.getElementById('pvCanvas');
  c.width=c.parentElement.clientWidth;c.height=80;
  var ctx=c.getContext('2d');
  ctx.fillStyle='#0f172a';ctx.fillRect(0,0,c.width,c.height);
  // Draw 60 seconds of transient pattern
  var pts=[];var maxP=0;
  for(var i=0;i<300;i++){
    var pw=i<240?eqPower(p,rated,i,300,1.0,Te,24):offPower(p,rated);
    pts.push(pw);if(pw>maxP)maxP=pw;
  }
  ctx.strokeStyle='#3b82f6';ctx.lineWidth=1.5;ctx.beginPath();
  pts.forEach(function(v,i){
    var x=i/300*c.width,y=c.height-5-(v/maxP)*(c.height-10);
    i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
  });ctx.stroke();
  // Labels
  ctx.fillStyle='#64748b';ctx.font='9px monospace';
  ctx.fillText('Spike: '+(rated*p.startupSpike).toFixed(0)+'W',4,12);
  ctx.fillText('Steady: '+(rated*0.6).toFixed(0)+'W',c.width/2,12);
  ctx.fillText('Off: '+(rated*p.standby).toFixed(0)+'W',c.width-80,12);
}

async function generate(){
  var btn=document.getElementById('btn');btn.disabled=true;
  document.getElementById('status').textContent='Generating...';
  document.getElementById('log').textContent='';
  var type=document.getElementById('eqType').value;
  var p=PROFILES[type];
  var Te=parseInt(document.getElementById('te').value);
  var rated=parseInt(document.getElementById('rated').value);
  var days=parseInt(document.getElementById('days').value);
  var waste=parseInt(document.getElementById('waste').value)/100;
  var startH=parseInt(document.getElementById('sh').value);
  var endH=parseInt(document.getElementById('eh').value);
  var intv=parseInt(document.getElementById('intv').value);
  var setpoint=24;
  log(p.name+' Simulator');
  log('Rated='+rated+'W Te='+Te+'\u00b0C Days='+days+' Waste='+Math.round(waste*100)+'%');
  log('Schedule: '+startH+':00-'+endH+':00 Interval: '+intv+'s');
  log('Transient: spike='+p.startupSpike+'x ramp='+p.transientPower+'x osc=\u00b1'+Math.round(p.steadyOsc*100)+'%');
  log('');
  var rows=[];
  var now=Date.now();
  var base=now-days*86400000;
  for(var d=0;d<days;d++){
    var dayStart=base+d*86400000;
    var dayTe=Te+(Math.random()-0.5)*4;
    var dayWaste=waste+(Math.random()-0.5)*0.15;
    var secInDay=0;
    for(var s=0;s<86400;s+=intv){
      var ts=new Date(dayStart+s*1000);
      var h=s/3600;
      var isOn=h>=startH&&h<endH;
      var power,state;
      if(isOn){
        var secInCycle=(h-startH)*3600;
        var cycleDur=(endH-startH)*3600;
        if(h>=endH-0.5){
          // Shutdown ramp
          state='SHUTDOWN';
          var shutProg=(h-(endH-0.5))/0.5;
          power=rated*dayWaste*0.5*(1-shutProg)+rated*p.shutdownSpike*(shutProg>0.9?1:0);
        } else {
          state=secInCycle<p.spikeDur+p.transientDur?'STARTUP':'RUNNING';
          power=eqPower(p,rated,secInCycle,cycleDur,dayWaste,dayTe,setpoint);
        }
      } else {
        state='OFF';
        power=offPower(p,rated);
      }
      power=Math.max(0,+power.toFixed(1));
      var ti=isOn?(setpoint+(Math.random()-0.5)*0.8):(dayTe-(dayTe-setpoint)*Math.exp(-0.3*Math.max(0,h-endH)));
      rows.push({timestamp:ts.toISOString(),power_w:power,temp_int:+(ti).toFixed(2),temp_ext:+(dayTe+(Math.random()-0.5)*0.5).toFixed(2),state:state});
    }
    log('Day '+(d+1)+': '+Math.round(86400/intv)+' readings (Te='+dayTe.toFixed(1)+'\u00b0C)');
  }
  log('');
  log('Total: '+rows.length+' readings');
  log('Inserting into power_consumption...');
  var ins=0,bs=50;
  for(var i=0;i<rows.length;i+=bs){
    var batch=rows.slice(i,i+bs);
    try{await sdk.insert('power_consumption',batch);ins+=batch.length;if(i%(bs*10)===0)log('  '+ins+'/'+rows.length)}catch(e){log('Error: '+e.message);break}
  }
  log('');
  log('\u2705 '+ins+' rows inserted');
  log('Equipment: '+p.name);
  log('States: STARTUP (spike+ramp) \u2192 RUNNING (steady+oscillation) \u2192 SHUTDOWN \u2192 OFF');
  log('');
  log('Now go to Energy Intelligence dashboard to analyze this data.');
  document.getElementById('status').textContent='Done: '+ins+' rows';
  btn.disabled=false;
}

updatePreview();
